+print(np.allclose(result, x, rtol=1e-10))
+"#
+        .into(),
+    );
+    let result = numpy_oracle(&script)?;
+    assert_eq!(result.trim(), "True", "log1p(expm1(x)) should equal x for small x");
+    Ok(())
+}
